
DO $$
DECLARE
  terminology_block TEXT := E'\n\n## ТЕРМИНОЛОГИЯ — ОБЯЗАТЕЛЬНЫЕ ПРАВИЛА ОБЪЯСНЕНИЯ И ЯЗЫКА\n\nПри упоминании перечисленных терминов в любом пояснительном тексте (комментарий к биомаркеру, вступление, резюме, назначения) действуй по правилам ниже. Пациент — не врач: без расшифровки термин непонятен.\n\n1. **Метилирование** — при первом упоминании в любом разделе давай короткое объяснение простым языком (1 предложение). Например: «метилирование — базовый биохимический процесс, при котором организм присоединяет метильную группу к ДНК, гормонам и токсинам; от него зависят обезвреживание, работа нервной системы и старение клеток». Не используй термин без объяснения.\n\n2. **Гемостаз** — при первом упоминании обязательно давай объяснение (1 предложение). Например: «гемостаз — система свёртывания крови, которая одновременно останавливает кровотечения и не даёт образовываться лишним тромбам». Не оставляй термин без расшифровки.\n\n3. **Гомоцистеин** — если упоминается для описания состояния/риска/связей, обязательно давай короткое объяснение (1 предложение). Например: «гомоцистеин — промежуточная аминокислота обмена метионина; его избыток повреждает стенку сосудов и связан с рисками для сердца, сосудов мозга и когнитивных функций». Не используй термин без объяснения.\n\n4. **Липопротеины — только полные русские названия в пояснениях**. В любом объясняющем/интерпретирующем тексте пиши развёрнуто по-русски:\n   - ЛПНП → «липопротеины низкой плотности»\n   - ЛПВП → «липопротеины высокой плотности»\n   - ЛПОНП → «липопротеины очень низкой плотности»\n   - Аббревиатуры ЛПНП/ЛПВП/ЛПОНП допустимы только в скобках после первого полного упоминания и в таблицах/названиях самих карточек биомаркеров.\n\n5. **Не использовать латинские сокращения в пояснительном тексте**. Категорически запрещено употреблять `VLDL`, `LDL`, `HDL`, `Lp(a)` и прочие латинские аббревиатуры внутри объясняющего текста — только русские названия («липопротеины очень низкой плотности» вместо VLDL, «липопротеины низкой плотности» вместо LDL и т.д.). Латиница допустима только в самих названиях карточек биомаркеров и в скобках-уточнениях.\n';
BEGIN
  UPDATE public.ai_prompt_settings
     SET prompt_text = prompt_text || terminology_block,
         updated_at = now()
   WHERE key IN (
     'global_biomarkers_instructions',
     'category_cardiovascular_system',
     'category_endocrine_system',
     'category_energy_system',
     'category_inflammation_system',
     'category_metabolism_system',
     'summary_system',
     'prescriptions_system'
   );
END $$;
